 function makeStore(configOverrides: Partial<AppConfig> = {}) {
   return configureStore({
     reducer: {
       chat: chatReducer,
       config: configReducer,
       prs: prsReducer,
     },
     preloadedState: {
       config: {
         config: {
           githubPat: '',
           llmApiKey: 'test-key',
           githubInstance: 'github.com',
           llmBackend: 'openai' as const,
           llmEndpoint: 'https://api.openai.com/v1',
           llmModel: 'gpt-4o',
           demoMode: false,
           summaryEnabled: true,
           summaryPrompt: 'summary prompt',
           summaryCommands: '',
           ...configOverrides,
         },
       },
       prs: {
         selectedPR: mockPR,
         activeRepository: { owner: 'org', repo: 'repo' },
         prList: [],
         files: [
           {
             sha: 'file-1',
             filename: 'src/file.ts',
             status: 'added' as const,
             additions: 1,
             deletions: 0,
             changes: 1,
             contents_url: '',
             patch: '@@ -0,0 +1 @@\n+const x = 1;',
           },
         ],
         comments: [],
         reviewComments: [],
         reviews: [],
         commits: [],
         summary: {
           status: 'idle' as const,
           content: null,
           generatedAt: null,
           error: null,
           requestKey: null,
           citations: [],
           hasUncitedContent: false,
         },
         signals: {
           status: 'idle' as const,
           data: null,
           error: null,
           requestKey: null,
         },
         isLoading: false,
         error: null,
         loadingByResource: {
           metadata: false,
           files: false,
           comments: false,
           reviewComments: false,
           reviews: false,
           commits: false,
           prList: false,
         },
         errorByResource: {
           metadata: null,
           files: null,
